INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", "やばいですね☆なの！", "ペコリーヌのプリン", 1, 100, 5, "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", "主さま、なの！", "コッコロのプリン", 2, 101, 5, "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", "ぶっ殺すぞ！なの！\n…デレデレはどこなの？", "キャルのプリン", 3, 102, 5, "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", "おにーたん♪なの！", "シェフィのプリン", 4, 103, 5, "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", "ハーハッハッハ！\n世界征服なのじゃなのー！", "イリヤのプリン", 5, 104, 5, "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", "お兄ちゃんのエッチ！　なの！", "アカリのプリン", 6, 105, 5, "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", "えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", "ヨリのプリン", 7, 106, 5, "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", "お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", "シノブのプリン", 8, 107, 5, "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", "インフェルノシールド！なの！", "ジュンのプリン", 9, 108, 5, "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", "あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", "トモのプリン", 10, 109, 5, "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", "タイガーヒーローボンバー！\nなの！", "マツリのプリン", 11, 110, 5, "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", "ま、いいんじゃん？\nしらんけどなの", "クロエのプリン", 13, 111, 5, "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", "ぷりーん★なの！", "チエルのプリン", 14, 112, 5, "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", "端的に換言すれば\n青春の味なの？", "ユニのプリン", 15, 113, 5, "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", "幼なじみはあんた…なの？", "サレンのプリン", 16, 114, 5, "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", "ひゃああんなの～！", "スズメのプリン", 17, 115, 5, "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", "サルキデバレヤ！なの！", "クルミのプリン", 18, 116, 5, "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", "プリンフルスイングなの～！", "アヤネのプリン", 19, 117, 5, "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", "みらくるみやりん\nくるりんぱ～☆なの！", "マホのプリン", 20, 118, 5, "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", "ウルフェンバイトなの！", "マコトのプリン", 21, 119, 5, "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", "なんくるないさ～！なの！", "カオリのプリン", 22, 120, 5, "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", "ふふん。簡単な推理なの", "カスミのプリン", 23, 121, 5, "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", "エリザベス～！なの～！", "マヒルのプリン", 24, 122, 5, "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", "私の好きな本…読んで\nもらえたらうれしいです…\nなの", "シオリのプリン", 25, 123, 5, "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", "もふもふにしてあげるなの！", "リマのプリン", 26, 124, 5, "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", "めんどくさいな～なの…", "リンのプリン", 27, 125, 5, "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", "プリンの権能を解放するの～！", "ラビリスタのプリン", 28, 126, 5, "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", "お姉ちゃんパワー全開！なの！", "シズルのプリン", 29, 127, 5, "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", "お兄ちゃん、プリンをよこすの！", "リノのプリン", 30, 128, 5, "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", "困った時はお互いさまさま！\nなの！", "ヒヨリのプリン", 31, 129, 5, "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", "フラワリングヒールなの～♪", "ユイのプリン", 32, 130, 5, "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", "スラッシュテンペスト！なの。", "レイのプリン", 33, 131, 5, "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", "おーほっほほほ！なの！", "アキノのプリン", 34, 132, 5, "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", "プリしゅわ最高～！なの！", "ユカリのプリン", 35, 133, 5, "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", "にゃにゃにゃ！なの！", "タマキのプリン", 36, 134, 5, "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", "効率全開！なの！", "ミフユのプリン", 37, 135, 5, "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", "あらあら～なの～♪", "ミサトのプリン", 38, 136, 5, "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", "スヤスヤ～…なの…", "ハツネのプリン", 39, 137, 5, "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", "ぼっちは卒業なの～！", "アオイのプリン", 40, 138, 5, "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", "リズムあげるのー！", "ノゾミのプリン", 41, 139, 5, "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", "風の加護を！なの！", "チカのプリン", 42, 140, 5, "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", "騎士さんのために\nしたんじゃありません！なの！", "ツムギのプリン", 43, 141, 5, "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", "宴の始まりなの！", "クリスティーナのプリン", 12, 142, 5, "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", "一刀両断、覚悟しな！なの！", "ルカのプリン", 44, 143, 5, "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", "きゅぴーん！キタコレ！なの！", "ナナカのプリン", 45, 144, 5, "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", "人呼んで、疾風のミヤコなの！", "アンナのプリン", 46, 145, 5, "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", "クスクス…クスクスクス…なの", "エリコのプリン", 47, 146, 5, "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", "どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", "ミツキのプリン", 48, 147, 5, "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", "私は子どもではない！なの！", "モニカのプリン", 49, 148, 5, "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", "ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", "ニノンのプリン", 50, 149, 5, "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", "…ぐふふ、じゅるり～なの", "クウカのプリン", 51, 150, 5, "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", "あぁ、ミヤコはなんて美しいの～", "ユキのプリン", 52, 151, 5, "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", "ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", "アユミのプリン", 53, 152, 5, "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", "にひひ…イタズラの時間なの！", "ミソギのプリン", 54, 153, 5, "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", "ぴょんぴょこぴょーん、なの♪", "ミミのプリン", 55, 154, 5, "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", "へんたいふしんしゃさんなの！", "キョウカのプリン", 56, 155, 5, "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", "ハート狙い撃ち！なの！", "スズナのプリン", 57, 156, 5, "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", "授業を始めます♪なの！", "イオのプリン", 58, 157, 5, "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", "立派なレディ、なの！", "ミサキのプリン", 59, 158, 5, "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", "プリンを持ってこないと\nお仕置きだよ～☆なの！", "ホマレのプリン", 60, 159, 5, "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", "たぎってきたの！", "カヤのプリン", 61, 160, 5, "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 3, "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", "下剋上、やってやるですなの！", "イノリのプリン", 62, 161, 5, "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", "どけどけ～！なの～！", "ムイミのプリン", 63, 162, 5, "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", "ミラーミラー！なの！", "ネネカのプリン", 64, 163, 5, "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", "プリンに忠誠を誓いますわ！\nなの！", "クレジッタのプリン", 65, 164, 5, "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 3, "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", "ギルド管理協会へようこそ！\nなの！", "カリンのプリン", 66, 165, 5, "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの");
